 {"id":"bd-y14","title":"Implement PromptTableRenderer for prompt registry display","description":"## Purpose and Rationale

Create a renderer that displays registered prompts in a beautiful format using rich_rust. Prompts are templated text that clients can request with arguments, useful for AI applications.

## Background

MCP prompts are parameterized text templates that clients can request and fill with arguments. They're particularly useful in AI contexts where consistent prompting patterns are needed. Displaying them clearly helps developers understand available prompt templates.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/handlers/prompt_table.rs

use rich_rust::{Table, Column, Panel, JustifyMethod, Style};
use crate::console::FastMcpConsole;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use fastmcp::prompt::PromptInfo;

/// Renders prompt registry as beautiful tables
pub struct PromptTableRenderer {
    theme: FastMcpTheme,
    context: DisplayContext,
    show_arguments: bool,
    show_preview: bool,
    preview_max_lines: usize,
}

impl PromptTableRenderer {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        Self {
            theme,
            context,
            show_arguments: true,
            show_preview: false,
            preview_max_lines: 3,
        }
    }

    /// Render prompts as a table
    pub fn render(&self, prompts: &[PromptInfo], console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_plain(prompts, console);
            return;
        }

        if prompts.is_empty() {
            console.print("[dim]No prompts registered[/]");
            return;
        }

        let mut table = Table::new()
            .title(format!("💬 Registered Prompts ({})", prompts.len()))
            .with_column(Column::new("Name").style(self.theme.primary_style()))
            .with_column(Column::new("Description").max_width(45))
            .with_column(Column::new("Arguments").justify(JustifyMethod::Center));

        for prompt in prompts {
            let name = &prompt.name;
            let desc = self.truncate(&prompt.description, 45);
            let args = self.format_arguments(&prompt.arguments);

            table.add_row_cells([name.as_str(), &desc, &args]);
        }

        console.print_renderable(&table);
    }

    /// Render a single prompt with full detail
    pub fn render_detail(&self, prompt: &PromptInfo, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_detail_plain(prompt, console);
            return;
        }

        // Prompt name header
        console.print(&format!("\n[bold magenta]{}[/]", prompt.name));
        console.print(&format!("[dim]{}[/]\n", prompt.description));

        // Arguments table
        if !prompt.arguments.is_empty() {
            let mut arg_table = Table::new()
                .title("Arguments")
                .with_column(Column::new("Name").style(self.theme.secondary_style()))
                .with_column(Column::new("Required").justify(JustifyMethod::Center))
                .with_column(Column::new("Description"));

            for arg in &prompt.arguments {
                let required = if arg.required { "✓" } else { "" };
                arg_table.add_row_cells([
                    arg.name.as_str(),
                    required,
                    arg.description.as_deref().unwrap_or(""),
                ]);
            }

            console.print_renderable(&arg_table);
        }

        // Template preview (if enabled)
        if self.show_preview {
            if let Some(template) = &prompt.template {
                console.print("\n[dim]Template Preview:[/]");

                let preview = self.preview_template(template);
                let panel = Panel::from_text(&preview)
                    .style(self.theme.dim_border_style());

                console.print_renderable(&panel);
            }
        }
    }

    fn format_arguments(&self, args: &[ArgumentInfo]) -> String {
        if args.is_empty() {
            "none".to_string()
        } else {
            let required = args.iter().filter(|a| a.required).count();
            let optional = args.len() - required;

            match (required, optional) {
                (r, 0) => format!("{} required", r),
                (0, o) => format!("{} optional", o),
                (r, o) => format!("{} req, {} opt", r, o),
            }
        }
    }

    fn preview_template(&self, template: &str) -> String {
        let lines: Vec<&str> = template.lines().take(self.preview_max_lines).collect();
        let preview = lines.join("\n");

        if template.lines().count() > self.preview_max_lines {
            format!("{}\n[dim]...[/]", preview)
        } else {
            preview
        }
    }

    fn truncate(&self, s: &str, max: usize) -> String {
        if s.len() <= max {
            s.to_string()
        } else {
            format!("{}...", &s[..max - 3])
        }
    }

    fn render_plain(&self, prompts: &[PromptInfo], console: &FastMcpConsole) {
        console.print(&format!("Registered Prompts ({})", prompts.len()));
        for prompt in prompts {
            console.print(&format!("  {} - {}", prompt.name, prompt.description));
        }
    }

    fn render_detail_plain(&self, prompt: &PromptInfo, console: &FastMcpConsole) {
        console.print(&format!("Prompt: {}", prompt.name));
        console.print(&format!("Description: {}", prompt.description));
        for arg in &prompt.arguments {
            let req = if arg.required { "required" } else { "optional" };
            console.print(&format!("  - {} ({})", arg.name, req));
        }
    }
}
